mapper.select:
/* 회사 목록 조회 */
select * from (
select
@rownum := @rownum + 1 as rnum,
page_tb.*
from (
select
comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_company
where del_yn = 'N'

    and comp_idx = #{compIdx }

) page_tb
, ( select @rownum := 0 ) r
order by reg_date desc
) f_tb

    limit #{startNum }, #{pageRowCnt }

/* 회사 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
			from tb_company
			where del_yn = 'N'
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 그룹 목록 조회 */
select * from (
select
@rownum := @rownum + 1 as rnum,
page_tb.*
from (
select
a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name,
a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname,
a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date
from tb_site_group a, tb_company b
where a.comp_idx = b.comp_idx
and a.del_yn = 'N'

    and a.comp_idx = #{compIdx }


    and a.site_grp_idx = #{siteGrpIdx }

) page_tb
, ( select @rownum := 0 ) r
order by reg_date desc
) f_tb

    limit #{startNum }, #{pageRowCnt }

/* 그룹 목록 건수 조회 */
select
count(*) as listCnt
from (
select
@rownum := @rownum + 1 as rnum,
page_tb.*
from (
select
a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name,
a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname,
a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date
from tb_site_group a, tb_company b
where a.comp_idx = b.comp_idx
and a.del_yn = 'N'

    and a.comp_idx = #{compIdx }


    and a.site_grp_idx = #{siteGrpIdx }

) page_tb
, ( select @rownum := 0 ) r
) f_tb

/* 사이트 목록 조회 */ select * from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.site_id, a.user_idx, a.site_name, a.site_grp_idx, a.area_type, a.`time_zone`, a.local_ems_addr, a.local_ems_key, a.local_ems_api_ver, a.comp_idx, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date , b.site_grp_name, c.device_type_nms from tb_site a left outer join tb_site_group b on a.site_grp_idx = b.site_grp_idx left outer join ( select site_id, group_concat(device_type_nm SEPARATOR ', ') as device_type_nms from ( select site_id, device_type, case device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' else '' end as device_type_nm from tb_device group by site_id, device_type ) a group by site_id ) c on a.site_id = c.site_id where a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
) page_tb , ( select @rownum := 0 ) r order by reg_date desc ) f_tb
limit #{startNum }, #{pageRowCnt }

/* 사이트 목록 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.site_id, a.user_idx, a.site_name, a.site_grp_idx, a.area_type, a.`time_zone`, a.local_ems_addr, a.local_ems_key, a.comp_idx, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date , b.site_grp_name, c.device_type_nms from tb_site a left outer join tb_site_group b on a.site_grp_idx = b.site_grp_idx left outer join ( select site_id, group_concat(device_type_nm) as device_type_nms from ( select site_id, device_type, case device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' when 6 then 'ESS모니터링기기' when 7 then 'iSmart' when 8 then '총량기기' else '' end as device_type_nm from tb_device group by site_id, device_type ) a group by site_id ) c on a.site_id = c.site_id where a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* 회사 내 그룹 목록(팝업) 조회 */ select a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name, a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date from tb_site_group a, tb_company b where a.comp_idx = b.comp_idx and a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
order by a.site_grp_name

/* 사이트 목록(사이트그룹 내) 조회 */
select
site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`,
local_ems_addr, local_ems_key, comp_idx, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_site
where del_yn = 'N'

    and comp_idx = #{compIdx}


    and site_grp_idx = #{siteGrpIdx }


    and site_id = #{siteId }

order by reg_date

/* 사이트 목록(고객사 전체중 특정사이트그룹 제외) 조회 */
select
site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`,
local_ems_addr, local_ems_key, comp_idx, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_site
where del_yn = 'N'

    and comp_idx = #{compIdx}


    and user_idx = #{userIdx }


    and (site_grp_idx != #{siteGrpIdx } or site_grp_idx is null)

order by reg_date

/* 상단 사이트그룹 목록 조회 */
select
site_grp_idx, user_idx, site_grp_id, site_grp_name, comp_idx
from tb_site_group
where del_yn = 'N'

    and comp_idx = #{compIdx}


    and site_grp_idx = #{siteGrpIdx}


    and user_idx = #{userIdx}

order by site_grp_name

/* 상단 사이트 목록 조회 */
select
a.site_id, a.site_name, a.site_grp_idx, a.comp_idx
from tb_site a, tb_site_group b
where a.site_grp_idx = b.site_grp_idx
and a.del_yn = 'N'

    and a.comp_idx = #{compIdx}


    and a.site_grp_idx = #{siteGrpIdx}


    and a.user_idx = #{userIdx}

order by a.site_name

/* 군관리메인 사이트 사용량 순위 목록 조회 */ select * from ( select a.site_id, a.site_name, ifnull(c.usg_val, 0) as "usage", ifnull(d.charge, 0) as charge, ifnull(e.gen_val, 0) as gen, ifnull(f.reward, 0) as reward, ifnull(g.usage_plan, 0) as usage_plan, ifnull(h.charge_plan, 0) as charge_plan from tb_site a left outer join (select site_id, ifnull(sum(usg_val), 0) as usg_val from tb_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) c on a.site_id = c.site_id left outer join (select site_id, (ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0)) as charge from tb_ess_charge where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) d on a.site_id = d.site_id left outer join (select site_id, ifnull(sum(gen_val), 0) as gen_val from tb_pv_gen where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) e on a.site_id = e.site_id left outer join ( select site_id, ifnull(sum(ess_chg_incen+ess_dischg_incen), 0) as reward from tb_bill_day where svc_stimestamp between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id
) f on a.site_id = f.site_id left outer join (select site_id, ifnull(sum(pre_usg_val), 0) as usage_plan from tb_predict_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) g on a.site_id = g.site_id left outer join (select site_id, ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) as charge_plan from tb_ess_charge_plan where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) h on a.site_id = h.site_id , tb_site_group b where a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.comp_idx = #{compIdx}
and a.site_grp_idx = #{siteGrpIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
and b.comp_idx = #{compIdx}
and b.site_grp_idx = #{siteGrpIdx}
) f_tb order by #{rankType} desc
limit #{startNum }, #{pageRowCnt }

/* 군관리메인 사이트 사용량 순위 목록 건수 조회 (군관리메인 사이트 목록 건수 조회와 동일) */
select
count(*) as listCnt
from (
select
a.site_id, a.site_name
from tb_site a, tb_site_group b
where a.site_grp_idx = b.site_grp_idx
and a.del_yn = 'N'

    
        
            and a.user_idx = #{userIdx}
        
        
            and a.comp_idx = #{compIdx}
        
        
            and a.site_grp_idx = #{siteGrpIdx}
        
        and a.area_type = #{areaType}
    
    
        
            and b.site_grp_idx = #{grpIdx}
        
        
            and b.user_idx = #{userIdx}
        
        
            and b.comp_idx = #{compIdx}
        
        
            and b.site_grp_idx = #{siteGrpIdx}
        
    

) f_tb

/* 군관리메인 지역별 사이트 건수 목록 조회 */
select
a.area_type, count(*) cnt
from tb_site a, tb_site_group b
where a.site_grp_idx = b.site_grp_idx
and a.del_yn = 'N'

    and a.user_idx = #{userIdx}


    and a.comp_idx = #{compIdx}


    and a.site_grp_idx = #{siteGrpIdx}

group by a.area_type

/* 군관리메인 사이트 목록 조회 */ select * from ( select a.site_id, a.site_name, b.site_grp_idx, (select count( case when device_type in ('4', '6', '7', '8') then 1 end ) from tb_device where site_id = a.site_id) ioe, (select count( case when device_type = '1' then 1 end ) from tb_device where site_id = a.site_id) pcs, (select count( case when device_type = '2' then 1 end ) from tb_device where site_id = a.site_id) bms, (select count( case when device_type in ('3', '5') then 1 end ) from tb_device where site_id = a.site_id) pv, ifnull(c.usg_val, 0) as usg, ifnull(d.charge, 0) as charge, ifnull(e.gen_val, 0) as gen, ifnull(f.reward, 0) as reward from tb_site a left outer join (select site_id, ifnull(sum(usg_val), 0) as usg_val from tb_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) c on a.site_id = c.site_id left outer join (select site_id, (ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0)) as charge from tb_ess_charge where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) d on a.site_id = d.site_id left outer join (select site_id, ifnull(sum(gen_val), 0) as gen_val from tb_pv_gen where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) e on a.site_id = e.site_id left outer join ( select site_id, ifnull(sum(ess_chg_incen+ess_dischg_incen), 0) as reward from tb_bill_day where svc_stimestamp between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id
) f on a.site_id = f.site_id , tb_site_group b where a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.comp_idx = #{compIdx}
and a.site_grp_idx = #{siteGrpIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
and b.comp_idx = #{compIdx}
and b.site_grp_idx = #{siteGrpIdx}
) f_tb order by usg desc
limit #{startNum }, #{pageRowCnt }

/* 군관리메인 사이트 목록 건수 조회 */
select
count(*) as listCnt
from (
select
a.site_id, a.site_name, b.site_grp_idx
from tb_site a, tb_site_group b
where a.site_grp_idx = b.site_grp_idx
and a.del_yn = 'N'

    
        
            and a.user_idx = #{userIdx}
        
        
            and a.comp_idx = #{compIdx}
        
        
            and a.site_grp_idx = #{siteGrpIdx}
        
        and a.area_type = #{areaType}
    
    
        
            and b.site_grp_idx = #{grpIdx}
        
        
            and b.user_idx = #{userIdx}
        
        
            and b.comp_idx = #{compIdx}
        
        
            and b.site_grp_idx = #{siteGrpIdx}
        
    

) f_tb

/* 군관리메인 사이트그룹 목록 조회 */
select
site_grp_idx, user_idx, site_grp_id, site_grp_name
from tb_site_group
where del_yn = 'N'

    and user_idx = #{userIdx}


    and comp_idx = #{compIdx}


    and site_grp_idx = #{siteGrpIdx}

order by site_grp_name

/* 회사 한건 조회 */
select 
	comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_company
where del_yn = 'N'
and comp_idx = #{compIdx }

/* 그룹 한건 조회 */
select 
	site_grp_idx, user_idx, site_grp_id, site_grp_name, comp_idx, site_grp_img_path, site_grp_img_sname, site_grp_img_rname, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site_group
where del_yn = 'N'
and site_grp_idx = #{siteGrpIdx }

/* 그룹ID 중복여부 체크 */
select 
	count(*) as cnt 
from tb_site_group
where site_grp_id = #{siteGrpId }

/* 군관리메인 사이트 사용량 순위 누적/예상 총합 조회 */ select sum(usg_val) "usage", sum(charge) charge, sum(gen) gen, sum(reward) reward, sum(usage_plan) usage_plan, sum(charge_plan) charge_plan from ( select ifnull(c.usg_val, 0) as usg_val, ifnull(d.charge, 0) as charge, ifnull(e.gen_val, 0) as gen, ifnull(f.reward, 0) as reward, ifnull(g.usage_plan, 0) as usage_plan, ifnull(h.charge_plan, 0) as charge_plan from tb_site a left outer join (select site_id, ifnull(sum(usg_val), 0) as usg_val from tb_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) c on a.site_id = c.site_id left outer join (select site_id, (ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0)) as charge from tb_ess_charge where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) d on a.site_id = d.site_id left outer join (select site_id, ifnull(sum(gen_val), 0) as gen_val from tb_pv_gen where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) e on a.site_id = e.site_id left outer join ( select site_id, ifnull(sum(ess_chg_incen+ess_dischg_incen), 0) as reward from tb_bill_day where svc_stimestamp between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id
) f on a.site_id = f.site_id left outer join (select site_id, ifnull(sum(pre_usg_val), 0) as usage_plan from tb_predict_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) g on a.site_id = g.site_id left outer join (select site_id, ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) as charge_plan from tb_ess_charge_plan where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) h on a.site_id = h.site_id , tb_site_group b where a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.comp_idx = #{compIdx}
and a.site_grp_idx = #{siteGrpIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
and b.comp_idx = #{compIdx}
and b.site_grp_idx = #{siteGrpIdx}
) f_tb

/* 군관리메인 사이트 사용량 총합계 조회 */ select site_grp_name, site_grp_img_path, site_grp_img_sname, sum(usg_val) "usage", sum(charge) charge, sum(gen) gen, sum(reward) reward from ( select b.site_grp_name, b.site_grp_img_path, b.site_grp_img_sname, ifnull(c.usg_val, 0) as usg_val, ifnull(d.charge, 0) as charge, ifnull(e.gen_val, 0) as gen, ifnull(f.reward, 0) as reward from tb_site a left outer join (select site_id, ifnull(sum(usg_val), 0) as usg_val from tb_usage where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) c on a.site_id = c.site_id left outer join (select site_id, (ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0)) as charge from tb_ess_charge where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) d on a.site_id = d.site_id left outer join (select site_id, ifnull(sum(gen_val), 0) as gen_val from tb_pv_gen where std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id) e on a.site_id = e.site_id left outer join ( select site_id, ifnull(sum(ess_chg_incen+ess_dischg_incen), 0) as reward from tb_bill_day where svc_stimestamp between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s') group by site_id
) f on a.site_id = f.site_id , tb_site_group b where a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.comp_idx = #{compIdx}
and a.site_grp_idx = #{siteGrpIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
and b.comp_idx = #{compIdx}
and b.site_grp_idx = #{siteGrpIdx}
) f_tb

mapper.update:
/* 회사 정보 수정 */ update tb_company set
comp_name = #{compName }, /* 회사명 */
comp_id = #{compId }, /* 회사ID */
mod_uid = #{modUid }, mod_date = now() where comp_idx = #{compIdx }

/* 그룹 삭제 */
delete from tb_site_group
where site_grp_idx = #{siteGrpIdx }

/* 사이트설정 삭제 */
delete from tb_site_set
where site_id = #{siteId }

/* 사이트 삭제 */
delete from tb_site
where site_id = #{siteId }
